   455→func (r *gitRepository) update(ctx context.Context, path string, data []byte, writer nanogit.StagedWriter) error {
   456→	// Check if trying to update a directory
   457→	if safepath.IsDir(path) {
   458→		return apierrors.NewBadRequest("cannot update a directory")
   459→	}
   460→
   461→	finalPath := safepath.Join(r.gitConfig.Path, path)
   462→	if _, err := writer.UpdateBlob(ctx, finalPath, data); err != nil {
   463→		if errors.Is(err, nanogit.ErrObjectNotFound) {
   464→			return repository.ErrFileNotFound
   465→		}
   466→
   467→		return fmt.Errorf("update blob: %w", mapNanogitError(err))
   468→	}
   469→
   470→	return nil
   471→}
