   611→func (r *gitRepository) ListRefs(ctx context.Context) ([]provisioning.RefItem, error) {
   612→	ctx, _ = r.withGitContext(ctx, "")
   613→	refs, err := r.client.ListRefs(ctx)
   614→	if err != nil {
   615→		return nil, fmt.Errorf("list refs: %w", err)
   616→	}
   617→	refItems := make([]provisioning.RefItem, 0, len(refs))
   618→	for _, ref := range refs {
   619→		// Only branches
   620→		if !strings.HasPrefix(ref.Name, "refs/heads/") {
   621→			continue
   622→		}
   623→
   624→		refItems = append(refItems, provisioning.RefItem{
   625→			Name: strings.TrimPrefix(ref.Name, "refs/heads/"),
   626→			Hash: ref.Hash.String(),
   627→		})
   628→	}
   629→
   630→	return refItems, nil
   631→}
