   643→func (r *gitRepository) CompareFiles(ctx context.Context, base, ref string) ([]repository.VersionedFileChange, error) {
   644→	if base == "" && ref == "" {
   645→		return nil, fmt.Errorf("base and ref cannot be empty")
   646→	}
   647→	if ref == "" {
   648→		return nil, fmt.Errorf("ref cannot be empty")
   649→	}
   650→
   651→	ctx, logger := r.withGitContext(ctx, ref)
   652→
   653→	// Resolve base ref to hash
   654→	var baseHash hash.Hash
   655→	if base != "" {
   656→		var err error
   657→		baseHash, err = r.resolveRefToHash(ctx, base)
   658→		if err != nil {
   659→			return nil, fmt.Errorf("resolve base ref: %w", err)
   660→		}
   661→	}
   662→
   663→	// Resolve ref to hash
   664→	refHash, err := r.resolveRefToHash(ctx, ref)
   665→	if err != nil {
   666→		return nil, fmt.Errorf("resolve ref: %w", err)
   667→	}
   668→
   669→	// Get commit hashes for base and ref
   670→	// Compare commits using nanogit
   671→	files, err := r.client.CompareCommits(ctx, baseHash, refHash)
   672→	if err != nil {
   673→		return nil, fmt.Errorf("compare commits: %w", err)
   674→	}
   675→
   676→	changes := make([]repository.VersionedFileChange, 0)
   677→	for _, f := range files {
   678→		switch f.Status {
   679→		case protocol.FileStatusAdded:
   680→			currentPath, err := safepath.RelativeTo(f.Path, r.gitConfig.Path)
   681→			if err != nil {
   682→				// do nothing as it's outside of configured path
   683→				continue
   684→			}
   685→
   686→			changes = append(changes, repository.VersionedFileChange{
   687→				Path:   currentPath,
   688→				Ref:    ref,
   689→				Action: repository.FileActionCreated,
   690→			})
   691→		case protocol.FileStatusModified:
   692→			currentPath, err := safepath.RelativeTo(f.Path, r.gitConfig.Path)
   693→			if err != nil {
   694→				// do nothing as it's outside of configured path
   695→				continue
   696→			}
   697→
   698→			changes = append(changes, repository.VersionedFileChange{
   699→				Path:   currentPath,
   700→				Ref:    ref,
   701→				Action: repository.FileActionUpdated,
   702→			})
   703→		case protocol.FileStatusDeleted:
   704→			currentPath, err := safepath.RelativeTo(f.Path, r.gitConfig.Path)
   705→			if err != nil {
   706→				// do nothing as it's outside of configured path
   707→				continue
   708→			}
   709→
   710→			changes = append(changes, repository.VersionedFileChange{
   711→				Ref:          ref,
   712→				PreviousRef:  base,
   713→				Path:         currentPath,
   714→				PreviousPath: currentPath,
   715→				Action:       repository.FileActionDeleted,
   716→			})
   717→		case protocol.FileStatusTypeChanged:
   718→			// Handle type changes as modifications
   719→			currentPath, err := safepath.RelativeTo(f.Path, r.gitConfig.Path)
   720→			if err != nil {
   721→				// do nothing as it's outside of configured path
   722→				continue
   723→			}
   724→
   725→			changes = append(changes, repository.VersionedFileChange{
   726→				Path:   currentPath,
   727→				Ref:    ref,
   728→				Action: repository.FileActionUpdated,
   729→			})
   730→		default:
   731→			logger.Error("ignore unhandled file", "file", f.Path, "status", string(f.Status))
   732→		}
   733→	}
   734→
   735→	return changes, nil
   736→}
