   282→// Read implements provisioning.Repository.
   283→func (r *gitRepository) Read(ctx context.Context, filePath, ref string) (*repository.FileInfo, error) {
   284→	ctx, _ = r.withGitContext(ctx, ref)
   285→	finalPath := safepath.Join(r.gitConfig.Path, filePath)
   286→
   287→	// Resolve ref to commit hash
   288→	refHash, err := r.resolveRefToHash(ctx, ref)
   289→	if err != nil {
   290→		return nil, err
   291→	}
   292→
   293→	// get root hash
   294→	// TODO: Fix GetTree in nanogit as it does not work commit hash
   295→	commit, err := r.client.GetCommit(ctx, refHash)
   296→	if err != nil {
   297→		return nil, fmt.Errorf("get commit: %w", mapNanogitError(err))
   298→	}
   299→
   300→	// Check if the path represents a directory
   301→	if safepath.IsDir(filePath) {
   302→		// Strip trailing slash for git tree lookup to avoid empty path components
   303→		finalPath = strings.TrimSuffix(finalPath, "/")
   304→		tree, err := r.client.GetTreeByPath(ctx, commit.Tree, finalPath)
   305→		if err != nil {
   306→			if errors.Is(err, nanogit.ErrObjectNotFound) {
   307→				return nil, repository.ErrFileNotFound
   308→			}
   309→
   310→			return nil, fmt.Errorf("get tree by path: %w", mapNanogitError(err))
   311→		}
   312→
   313→		return &repository.FileInfo{
   314→			Path: filePath,
   315→			Ref:  refHash.String(),
   316→			Hash: tree.Hash.String(),
   317→		}, nil
   318→	}
   319→
   320→	blob, err := r.client.GetBlobByPath(ctx, commit.Tree, finalPath)
   321→	if err != nil {
   322→		if errors.Is(err, nanogit.ErrObjectNotFound) {
   323→			return nil, repository.ErrFileNotFound
   324→		}
   325→
   326→		return nil, fmt.Errorf("read blob: %w", mapNanogitError(err))
   327→	}
   328→
   329→	return &repository.FileInfo{
   330→		Path: filePath,
   331→		Ref:  ref,
   332→		Data: blob.Content,
   333→		Hash: blob.Hash.String(),
   334→	}, nil
   335→}
