   382→func (r *gitRepository) Create(ctx context.Context, path, ref string, data []byte, comment string) error {
   383→	if ref == "" {
   384→		ref = r.gitConfig.Branch
   385→	}
   386→	ctx, _ = r.withGitContext(ctx, ref)
   387→	branchRef, err := r.ensureBranchExists(ctx, ref)
   388→	if err != nil {
   389→		return err
   390→	}
   391→
   392→	writer, err := r.client.NewStagedWriter(ctx, branchRef)
   393→	if err != nil {
   394→		return fmt.Errorf("create staged writer: %w", mapNanogitError(err))
   395→	}
   396→
   397→	if err := r.create(ctx, path, data, writer); err != nil {
   398→		return err
   399→	}
   400→
   401→	return r.commitAndPush(ctx, writer, comment)
   402→}
