   427→func (r *gitRepository) Update(ctx context.Context, path, ref string, data []byte, comment string) error {
   428→	if ref == "" {
   429→		ref = r.gitConfig.Branch
   430→	}
   431→	ctx, _ = r.withGitContext(ctx, ref)
   432→
   433→	// Check if trying to update a directory
   434→	if safepath.IsDir(path) {
   435→		return apierrors.NewBadRequest("cannot update a directory")
   436→	}
   437→
   438→	branchRef, err := r.ensureBranchExists(ctx, ref)
   439→	if err != nil {
   440→		return err
   441→	}
   442→	// Create a staged writer
   443→	writer, err := r.client.NewStagedWriter(ctx, branchRef)
   444→	if err != nil {
   445→		return fmt.Errorf("create staged writer: %w", mapNanogitError(err))
   446→	}
   447→
   448→	if err := r.update(ctx, path, data, writer); err != nil {
   449→		return err
   450→	}
   451→
   452→	return r.commitAndPush(ctx, writer, comment)
   453→}
