   618→	for _, ref := range refs {
   619→		// Only branches
   620→		if !strings.HasPrefix(ref.Name, "refs/heads/") {
   621→			continue
   622→		}
   623→
   624→		refItems = append(refItems, provisioning.RefItem{
   625→			Name: strings.TrimPrefix(ref.Name, "refs/heads/"),
   626→			Hash: ref.Hash.String(),
   627→		})
   628→	}
   629→
   630→	return refItems, nil
   631→}
