   643→func (r *gitRepository) CompareFiles(ctx context.Context, base, ref string) ([]repository.VersionedFileChange, error) {
   644→	if base == "" && ref == "" {
   645→		return nil, fmt.Errorf("base and ref cannot be empty")
   646→	}
   647→	if ref == "" {
   648→		return nil, fmt.Errorf("ref cannot be empty")
   649→	}
   650→
   651→	ctx, logger := r.withGitContext(ctx, ref)
   652→
   653→	// Resolve base ref to hash
   654→	var baseHash hash.Hash
   655→	if base != "" {
   656→		var err error
   657→		baseHash, err = r.resolveRefToHash(ctx, base)
   658→		if err != nil {
   659→			return nil, fmt.Errorf("resolve base ref: %w", err)
   660→		}
   661→	}
   662→
   663→	// Resolve ref to hash
   664→	refHash, err := r.resolveRefToHash(ctx, ref)
   665→	if err != nil {
   666→		return nil, fmt.Errorf("resolve ref: %w", err)
   667→	}
   668→
   669→	// Get commit hashes for base and ref
   670→	// Compare commits using nanogit
   671→	files, err := r.client.CompareCommits(ctx, baseHash, refHash)
   672→	if err != nil {
   673→		return nil, fmt.Errorf("compare commits: %w", err)
   674→	}
   675→
   676→	changes := make([]repository.VersionedFileChange, 0)
   677→	for _, f := range files {
   678→		switch f.Status {
   679→		case protocol.FileStatusAdded:
   680→			currentPath, err := safepath.RelativeTo(f.Path, r.gitConfig.Path)
   681→			if err != nil {
   682→				// do nothing as it's outside of configured path
   683→				continue
   684→			}
   685→
   686→			changes = append(changes, repository.VersionedFileChange{
   687→				Path:   currentPath,
   688→				Ref:    ref,
   689→				Action: repository.FileActionCreated,
   690→			})
   691→		case protocol.FileStatusModified:
   692→			currentPath, err := safepath.RelativeTo(f.Path, r.gitConfig.Path)
   693→			if err != nil {
   694→				// do nothing as it's outside of configured path
   695→				continue
   696→			}
   697→
   698→			changes = append(changes, repository.VersionedFileChange{
   699→				Path:   currentPath,
   700→				Ref:    ref,
   701→				Action: repository.FileActionUpdated,
   702→			})
   703→		case protocol.FileStatusDeleted:
   704→			currentPath, err := safepath.RelativeTo(f.Path, r.gitConfig.Path)
   705→			if err != nil {
   706→				// do nothing as it's outside of configured path
   707→				continue
   708→			}
   709→
   710→			changes = append(changes, repository.VersionedFileChange{
   711→				Ref:          ref,
   712→				PreviousRef:  base,
   713→				Path:         currentPath,
   714→				PreviousPath: currentPath,
   715→				Action:       repository.FileActionDeleted,
   716→			})
   717→		case protocol.FileStatusTypeChanged:
   718→			// Handle type changes as modifications
   719→			currentPath, err := safepath.RelativeTo(f.Path, r.gitConfig.Path)
   720→			if err != nil {
   721→				// do nothing as it's outside of configured path
   722→				continue
   723→			}
   724→
   725→			changes = append(changes, repository.VersionedFileChange{
   726→				Path:   currentPath,
   727→				Ref:    ref,
   728→				Action: repository.FileActionUpdated,
   729→			})
   730→		default:
   731→			logger.Error("ignore unhandled file", "file", f.Path, "status", string(f.Status))
   732→		}
   733→	}
   734→
   735→	return changes, nil
   736→}
   737→
   738→func (r *gitRepository) Stage(ctx context.Context, opts repository.StageOptions) (repository.StagedRepository, error) {
   739→	ctx = ensureRetryContext(ctx)
   740→	ctx, _ = r.withGitContext(ctx, "")
   741→	return NewStagedGitRepository(ctx, r, opts)
   742→}
   743→
   744→// resolveRefToHash resolves a ref (branch name or commit hash) to a commit hash
   745→func (r *gitRepository) resolveRefToHash(ctx context.Context, ref string) (hash.Hash, error) {
   746→	ctx, _ = r.withGitContext(ctx, ref)
   747→
   748→	// Use default branch if ref is empty
   749→	if ref == "" {
   750→		ref = r.gitConfig.Branch
   751→	}
   752→
   753→	// Try to parse ref as a hash first
   754→	refHash, err := hash.FromHex(ref)
   755→	if err == nil && refHash != hash.Zero {
   756→		// Valid hash, return it
   757→		return refHash, nil
   758→	}
   759→
   760→	// Prefix ref with refs/heads/
   761→	ref = fmt.Sprintf("refs/heads/%s", ref)
   762→
   763→	// Not a valid hash, try to resolve as a branch reference
   764→	branchRef, err := r.client.GetRef(ctx, ref)
   765→	if err != nil {
   766→		if errors.Is(err, nanogit.ErrObjectNotFound) {
   767→			return hash.Zero, fmt.Errorf("ref not found: %s: %w", ref, repository.ErrRefNotFound)
   768→		}
   769→		return hash.Zero, fmt.Errorf("get ref %s: %w", ref, mapNanogitError(err))
   770→	}
   771→
   772→	return branchRef.Hash, nil
   773→}
   774→
   775→// ensureBranchExists checks if a branch exists and creates it if it doesn't,
   776→// returning the branch reference to avoid duplicate GetRef calls
   777→func (r *gitRepository) ensureBranchExists(ctx context.Context, branchName string) (nanogit.Ref, error) {
   778→	ctx, _ = r.withGitContext(ctx, branchName)
   779→
   780→	if !IsValidGitBranchName(branchName) {
   781→		return nanogit.Ref{}, &apierrors.StatusError{
   782→			ErrStatus: metav1.Status{
   783→				Code:    http.StatusBadRequest,
   784→				Message: "invalid branch name",
   785→			},
   786→		}
   787→	}
   788→
   789→	// Check if branch exists by trying to get the branch reference
   790→	branchRef, err := r.client.GetRef(ctx, fmt.Sprintf("refs/heads/%s", branchName))
   791→	if err == nil {
   792→		// Branch exists, return it
   793→		logging.FromContext(ctx).Info("branch already exists", "branch", branchName)
   794→		return branchRef, nil
   795→	}
   796→
   797→	// If error is not "ref not found", return the error
   798→	if !errors.Is(err, nanogit.ErrObjectNotFound) {
   799→		return nanogit.Ref{}, fmt.Errorf("check branch exists: %w", err)
   800→	}
   801→
   802→	// Branch doesn't exist, create it based on the configured branch
   803→	srcBranch := r.gitConfig.Branch
   804→	srcRef, err := r.client.GetRef(ctx, fmt.Sprintf("refs/heads/%s", srcBranch))
   805→	if err != nil {
   806→		return nanogit.Ref{}, fmt.Errorf("get source branch ref: %w", err)
   807→	}
   808→
   809→	// Create the new branch reference
   810→	newRef := nanogit.Ref{
   811→		Name: fmt.Sprintf("refs/heads/%s", branchName),
   812→		Hash: srcRef.Hash,
   813→	}
   814→
   815→	if err := r.client.CreateRef(ctx, newRef); err != nil {
   816→		return nanogit.Ref{}, fmt.Errorf("create branch: %w", err)
   817→	}
   818→
   819→	return newRef, nil
   820→}
   821→
   822→// createSignature creates author and committer signatures using the context signature if available,
   823→// falling back to default Grafana signature
   824→func (r *gitRepository) createSignature(ctx context.Context) (nanogit.Author, nanogit.Committer) {
   825→	author := nanogit.Author{
   826→		Name:  "Grafana",
   827→		Email: "noreply@grafana.com",
   828→		Time:  time.Now(),
   829→	}
   830→
   831→	// Use signature from context if available
   832→	if sig := repository.GetAuthorSignature(ctx); sig != nil {
   833→		if sig.Name != "" {
   834→			author.Name = sig.Name
   835→		}
   836→		if sig.Email != "" {
   837→			author.Email = sig.Email
   838→		}
   839→		if !sig.When.IsZero() {
   840→			author.Time = sig.When
   841→		}
   842→	}
   843→
   844→	if author.Time.IsZero() {
   845→		author.Time = time.Now()
   846→	}
   847→
   848→	// Author and committer are always the same (for now)
   849→	return author, nanogit.Committer(author)
   850→}
   851→
   852→func (r *gitRepository) commit(ctx context.Context, writer nanogit.StagedWriter, comment string) error {
   853→	author, committer := r.createSignature(ctx)
   854→	if _, err := writer.Commit(ctx, comment, author, committer); err != nil {
   855→		if errors.Is(err, nanogit.ErrNothingToCommit) {
   856→			return repository.ErrNothingToCommit
   857→		}
   858→
   859→		return fmt.Errorf("commit changes: %w", err)
   860→	}
   861→	return nil
   862→}
   863→
   864→func (r *gitRepository) commitAndPush(ctx context.Context, writer nanogit.StagedWriter, comment string) error {
   865→	if err := r.commit(ctx, writer, comment); err != nil {
   866→		return err
   867→	}
   868→
   869→	if err := writer.Push(ctx); err != nil {
   870→		return fmt.Errorf("push changes: %w", mapNanogitError(err))
   871→	}
   872→
   873→	return nil
   874→}
   875→
   876→// defaultGitRetrier returns a default retrier configuration for Git operations.
   877→//
   878→// Retry attempts will happen when:
   879→//   - Network errors occur: connection timeouts, temporary network failures, or connection errors
   880→//   - HTTP 5xx server errors: For GET and DELETE operations (idempotent)
   881→//   - HTTP 429 Too Many Requests: For all operations (rate limiting is temporary)
   882→//
   883→// The retry behavior:
   884→//   - Total attempts: 8 (1 initial attempt + 7 retries)
   885→//   - Initial delay: 100ms before the first retry
   886→//   - Exponential backoff: delay doubles after each failed attempt (100ms → 200ms → 400ms → 800ms → 1.6s → 3.2s → 5s)
   887→//   - Maximum delay: capped at 5 seconds
   888→//   - Jitter: enabled to prevent thundering herd problems
   889→//   - Total retry window: approximately 10 seconds from first attempt to last retry
   890→//
   891→// All attempts will fail when:
   892→//   - The Git server is completely unavailable or unreachable
   893→//   - Network connectivity issues persist beyond the retry window (~10 seconds)
   894→//   - The server returns transient errors consistently for the entire retry duration
   895→//   - Context cancellation occurs before retries complete
   896→//
   897→// Non-transient errors (e.g., 4xx client errors except 429, authentication failures) are not retried and returned immediately.
   898→func defaultGitRetrier() *retry.ExponentialBackoffRetrier {
   899→	return retry.NewExponentialBackoffRetrier().
   900→		WithMaxAttempts(8). // 1 initial + 7 retries = 8 total attempts (~10s total retry window)
   901→		WithInitialDelay(100 * time.Millisecond).
   902→		WithMaxDelay(5 * time.Second).
   903→		WithMultiplier(2.0).
   904→		WithJitter()
   905→}
   906→
   907→// ensureRetryContext ensures that retry logic is configured in the context.
   908→// This function should be called at the beginning of all methods that make client calls
   909→// to guarantee retry logic is always present, regardless of context state.
   910→func ensureRetryContext(ctx context.Context) context.Context {
   911→	// Only add retrier if one doesn't already exist in the context
   912→	if retry.FromContext(ctx).MaxAttempts() <= 1 {
   913→		ctx = retry.ToContext(ctx, defaultGitRetrier())
   914→	}
   915→	return ctx
   916→}
   917→
   918→// withGitContext sets up the context with logging, git repository metadata, and retry logic.
   919→// This function should be called at the beginning of all public methods to ensure:
   920→// - Proper logging context with git repository details
   921→// - Retry logic is configured for all Git operations
   922→// - Context is properly prepared for nanogit client calls
   923→func (r *gitRepository) withGitContext(ctx context.Context, ref string) (context.Context, logging.Logger) {
   924→	// Ensure retry logic is configured first, before any early returns
   925→	ctx = ensureRetryContext(ctx)
   926→
   927→	logger := logging.FromContext(ctx)
   928→
   929→	type containsGit int
   930→	var containsGitKey containsGit
   931→	if ctx.Value(containsGitKey) != nil {
   932→		return ctx, logging.FromContext(ctx)
   933→	}
   934→
   935→	if ref == "" {
   936→		ref = r.gitConfig.Branch
   937→	}
   938→	logger = logger.With(slog.Group("git_repository", "url", r.gitConfig.URL, "ref", ref, "nanogit", true))
   939→	ctx = logging.Context(ctx, logger)
   940→	// We want to ensure we don't add multiple git_repository keys. With doesn't deduplicate the keys...
   941→	ctx = context.WithValue(ctx, containsGitKey, true)
   942→
   943→	ctx = log.ToContext(ctx, logger)
   944→
   945→	return ctx, logger
   946→}
   947→
   948→// mapNanogitError converts nanogit-specific errors to repository errors.
   949→// This maintains the abstraction boundary and allows proper HTTP status code handling.
   950→func mapNanogitError(err error) error {
   951→	if err == nil {
   952→		return nil
   953→	}
   954→
   955→	// Map structured nanogit errors to repository errors using the sentinel errors
   956→	// from the client package (nanogit re-exports error types but not sentinel errors)
   957→	if errors.Is(err, client.ErrUnauthorized) {
   958→		return repository.ErrUnauthorized
   959→	}
   960→	if errors.Is(err, client.ErrPermissionDenied) {
   961→		return repository.ErrPermissionDenied
   962→	}
   963→	if errors.Is(err, client.ErrServerUnavailable) {
   964→		return repository.ErrServerUnavailable
   965→	}
   966→
   967→	// Return original error if not a known nanogit error
   968→	return err
   969→}
   970→
   971→// checkHTTPError checks if the error is a known HTTP error (401, 403, 503) and returns
   972→// the appropriate TestResults. Returns nil if the error is not a known HTTP error.
   973→func checkHTTPError(err error, fieldPath *field.Path) *provisioning.TestResults {
   974→	if err == nil {
   975→		return nil
   976→	}
   977→
   978→	if errors.Is(err, repository.ErrUnauthorized) {
   979→		return &provisioning.TestResults{
   980→			Code:    http.StatusUnauthorized,
   981→			Success: false,
   982→			Errors: []provisioning.ErrorDetails{{
   983→				Type:   metav1.CauseTypeFieldValueInvalid,
   984→				Field:  field.NewPath("secure", "token").String(),
   985→				Detail: "authentication failed",
   986→			}},
   987→		}
   988→	}
   989→
   990→	if errors.Is(err, repository.ErrPermissionDenied) {
   991→		return &provisioning.TestResults{
   992→			Code:    http.StatusForbidden,
   993→			Success: false,
   994→			Errors: []provisioning.ErrorDetails{{
   995→				Type:   metav1.CauseTypeFieldValueInvalid,
   996→				Field:  field.NewPath("secure", "token").String(),
   997→				Detail: "permission denied",
   998→			}},
   999→		}
  1000→	}
  1001→
  1002→	if errors.Is(err, repository.ErrServerUnavailable) {
  1003→		return &provisioning.TestResults{
  1004→			Code:    http.StatusServiceUnavailable,
  1005→			Success: false,
  1006→			Errors: []provisioning.ErrorDetails{{
  1007→				Type:   metav1.CauseTypeFieldValueInvalid,
  1008→				Field:  fieldPath.String(),
  1009→				Detail: fmt.Sprintf("server unavailable: %v", err),
  1010→			}},
  1011→		}
  1012→	}
  1013→
  1014→	return nil
  1015→}
