   148→func isValidGitURL(gitURL string) bool {
   149→	// Parse URL
   150→	parsed, err := url.Parse(gitURL)
   151→	if err != nil {
   152→		return false
   153→	}
   154→
   155→	// Must be HTTPS or HTTP (HTTP allowed for local development)
   156→	if parsed.Scheme != "https" && parsed.Scheme != "http" {
   157→		return false
   158→	}
   159→
   160→	// Must have a host
   161→	if parsed.Host == "" {
   162→		return false
   163→	}
   164→
   165→	// Must have a path
   166→	if parsed.Path == "" || parsed.Path == "/" {
   167→		return false
   168→	}
   169→
   170→	return true
   171→}
