   173→// Test implements provisioning.Repository.
   174→func (r *gitRepository) Test(ctx context.Context) (*provisioning.TestResults, error) {
   175→	ctx, _ = r.withGitContext(ctx, "")
   176→
   177→	t := string(r.config.Spec.Type)
   178→
   179→	// In case the branch is empty
   180→	if r.GetCurrentBranch() == "" {
   181→		branch, err := r.GetDefaultBranch(ctx)
   182→		if err != nil {
   183→			return nil, err
   184→		}
   185→
   186→		r.SetBranch(branch)
   187→	}
   188→
   189→	// Check authorization
   190→	if ok, err := r.client.IsAuthorized(ctx); err != nil || !ok {
   191→		// Map nanogit errors to repository errors for proper HTTP status codes
   192→		if err != nil {
   193→			err = mapNanogitError(err)
   194→			if result := checkHTTPError(err, field.NewPath("secure", "token")); result != nil {
   195→				return result, nil
   196→			}
   197→		}
   198→
   199→		detail := "not authorized"
   200→		if err != nil {
   201→			detail = fmt.Sprintf("failed check if authorized: %v", err)
   202→		}
   203→
   204→		return &provisioning.TestResults{
   205→			Code:    http.StatusBadRequest,
   206→			Success: false,
   207→			Errors: []provisioning.ErrorDetails{{
   208→				Type:   metav1.CauseTypeFieldValueInvalid,
   209→				Field:  field.NewPath("secure", "token").String(),
   210→				Detail: detail,
   211→			}},
   212→		}, nil
   213→	}
   214→
   215→	// Check if repository exists
   216→	if ok, err := r.client.RepoExists(ctx); err != nil || !ok {
   217→		// Map nanogit errors to repository errors for proper HTTP status codes
   218→		if err != nil {
   219→			err = mapNanogitError(err)
   220→			if result := checkHTTPError(err, field.NewPath("spec", t, "url")); result != nil {
   221→				return result, nil
   222→			}
   223→		}
   224→
   225→		detail := "repository not found"
   226→		if err != nil {
   227→			detail = fmt.Sprintf("failed check if repository exists: %v", err)
   228→		}
   229→
   230→		return &provisioning.TestResults{
   231→			Code:    http.StatusBadRequest,
   232→			Success: false,
   233→			Errors: []provisioning.ErrorDetails{{
   234→				Type:   metav1.CauseTypeFieldValueInvalid,
   235→				Field:  field.NewPath("spec", t, "url").String(),
   236→				Detail: detail,
   237→			}},
   238→		}, nil
   239→	}
   240→
   241→	// Test basic connectivity by getting the branch reference
   242→	_, err := r.client.GetRef(ctx, fmt.Sprintf("refs/heads/%s", r.gitConfig.Branch))
   243→	if err != nil {
   244→		// Check for branch not found first (before mapping)
   245→		if errors.Is(err, nanogit.ErrObjectNotFound) {
   246→			return &provisioning.TestResults{
   247→				Code:    http.StatusBadRequest,
   248→				Success: false,
   249→				Errors: []provisioning.ErrorDetails{{
   250→					Type:   metav1.CauseTypeFieldValueInvalid,
   251→					Field:  field.NewPath("spec", t, "branch").String(),
   252→					Detail: "branch not found",
   253→				}},
   254→			}, nil
   255→		}
   256→
   257→		// Map nanogit errors to repository errors for proper HTTP status codes
   258→		err = mapNanogitError(err)
   259→		if result := checkHTTPError(err, field.NewPath("spec", t, "branch")); result != nil {
   260→			return result, nil
   261→		}
   262→
   263→		detail := fmt.Sprintf("failed to check if branch exists: %v", err)
   264→
   265→		return &provisioning.TestResults{
   266→			Code:    http.StatusBadRequest,
   267→			Success: false,
   268→			Errors: []provisioning.ErrorDetails{{
   269→				Type:   metav1.CauseTypeFieldValueInvalid,
   270→				Field:  field.NewPath("spec", t, "branch").String(),
   271→				Detail: detail,
   272→			}},
   273→		}, nil
   274→	}
   275→
   276→	return &provisioning.TestResults{
   277→		Code:    http.StatusOK,
   278→		Success: true,
   279→	}, nil
   280→}
