   404→func (r *gitRepository) create(ctx context.Context, path string, data []byte, writer nanogit.StagedWriter) error {
   405→	finalPath := safepath.Join(r.gitConfig.Path, path)
   406→	// Create .keep file if it is a directory
   407→	if safepath.IsDir(finalPath) {
   408→		if data != nil {
   409→			return apierrors.NewBadRequest("data cannot be provided for a directory")
   410→		}
   411→
   412→		finalPath = safepath.Join(finalPath, ".keep")
   413→		data = []byte{}
   414→	}
   415→
   416→	if _, err := writer.CreateBlob(ctx, finalPath, data); err != nil {
   417→		if errors.Is(err, nanogit.ErrObjectAlreadyExists) {
   418→			return repository.ErrFileAlreadyExists
   419→		}
   420→
   421→		return fmt.Errorf("create blob: %w", mapNanogitError(err))
   422→	}
   423→
   424→	return nil
   425→}
